"""
TDD tests for SQLite database seed script.

Approach: Red/Green/Refactor cycle
- Each test is written FIRST (red), then implementation code is written to make it pass (green).
- Tests are grouped by functionality: schema, data generation, insertion, verification queries.
"""

import unittest
import sqlite3
import os
import tempfile


class TestSchemaCreation(unittest.TestCase):
    """Test that the database schema is created correctly with all tables and foreign keys."""

    def setUp(self):
        """Create a temporary database for each test."""
        self.db_fd, self.db_path = tempfile.mkstemp(suffix=".db")
        # Import will fail until we create the module -- this is the RED phase
        from db_seed import create_schema
        self.conn = sqlite3.connect(self.db_path)
        create_schema(self.conn)

    def tearDown(self):
        self.conn.close()
        os.close(self.db_fd)
        os.unlink(self.db_path)

    def test_users_table_exists(self):
        """RED: users table should exist with expected columns."""
        cursor = self.conn.execute(
            "SELECT name FROM sqlite_master WHERE type='table' AND name='users'"
        )
        self.assertIsNotNone(cursor.fetchone(), "users table should exist")

    def test_products_table_exists(self):
        """RED: products table should exist with expected columns."""
        cursor = self.conn.execute(
            "SELECT name FROM sqlite_master WHERE type='table' AND name='products'"
        )
        self.assertIsNotNone(cursor.fetchone(), "products table should exist")

    def test_orders_table_exists(self):
        """RED: orders table should exist with expected columns."""
        cursor = self.conn.execute(
            "SELECT name FROM sqlite_master WHERE type='table' AND name='orders'"
        )
        self.assertIsNotNone(cursor.fetchone(), "orders table should exist")

    def test_users_columns(self):
        """RED: users table should have id, name, email, created_at columns."""
        cursor = self.conn.execute("PRAGMA table_info(users)")
        columns = {row[1] for row in cursor.fetchall()}
        expected = {"id", "name", "email", "created_at"}
        self.assertEqual(columns, expected, f"users columns should be {expected}")

    def test_products_columns(self):
        """RED: products table should have id, name, price, category, stock columns."""
        cursor = self.conn.execute("PRAGMA table_info(products)")
        columns = {row[1] for row in cursor.fetchall()}
        expected = {"id", "name", "price", "category", "stock"}
        self.assertEqual(columns, expected, f"products columns should be {expected}")

    def test_orders_columns(self):
        """RED: orders table should have id, user_id, product_id, quantity, total_price, order_date."""
        cursor = self.conn.execute("PRAGMA table_info(orders)")
        columns = {row[1] for row in cursor.fetchall()}
        expected = {"id", "user_id", "product_id", "quantity", "total_price", "order_date"}
        self.assertEqual(columns, expected, f"orders columns should be {expected}")

    def test_foreign_keys_exist(self):
        """RED: orders table should have foreign keys to users and products."""
        cursor = self.conn.execute("PRAGMA foreign_key_list(orders)")
        fks = cursor.fetchall()
        # Each FK row: (id, seq, table, from, to, on_update, on_delete, match)
        referenced_tables = {row[2] for row in fks}
        self.assertIn("users", referenced_tables, "orders should reference users")
        self.assertIn("products", referenced_tables, "orders should reference products")

    def test_unique_email_constraint(self):
        """RED: users.email should be unique."""
        self.conn.execute(
            "INSERT INTO users (name, email, created_at) VALUES ('A', 'a@test.com', '2024-01-01')"
        )
        with self.assertRaises(sqlite3.IntegrityError):
            self.conn.execute(
                "INSERT INTO users (name, email, created_at) VALUES ('B', 'a@test.com', '2024-01-01')"
            )


if __name__ == "__main__":
    unittest.main()

